// Canvas context validation
function initializeCanvas(canvas) {
  const ctx = canvas.getContext('2d');
  if (!ctx) {
    throwError('Failed to get 2D context', 'initializeCanvas', 'Canvas may not support 2D rendering');
  }
  return ctx;
}

